+            Some(rebuilt_path)
+        } else {
+            None
+        }
+    } else {
+        None
+    };
+
+    ShortestPathResult {
+        path,
+        witness: ComplexityWitness {
+            algorithm: "dijkstra_shortest_path_directed".to_owned(),
+            complexity_claim: "O(|E| log |V|)".to_owned(),
+            nodes_touched,
+            edges_scanned,
+            queue_peak: queue_peak.max(ordered_nodes.len().min(queue_peak)),
+        },
+    }
